  (
  ([__temp,__restore] = _withAsyncContext(() => loadManagedContext())),
  await __temp,
  __restore()
)
} catch (error: unknown) {
  pageError.value = getApiErrorMessage(error, 'Production dashboard section is unavailable right now.')
} finally {
